  1→use anyhow::{Context, Result};
  2→use chrono::{DateTime, Utc};
  3→use serde::{Deserialize, Serialize};
  4→use std::fs;
  5→use std::io::Write;
  6→
  7→#[derive(Debug, Clone, Serialize, Deserialize)]
  8→pub struct StateEntry {
  9→    pub phase: String,
 10→    /// Sub-phase number if this is a sub-phase entry (e.g., "05.1")
 11→    #[serde(default, skip_serializing_if = "Option::is_none")]
 12→    pub sub_phase: Option<String>,
 13→    pub iteration: u32,
 14→    pub status: String,
 15→    pub timestamp: DateTime<Utc>,
 16→}
 17→
 18→impl StateEntry {
 19→    /// Check if this is a sub-phase entry.
 20→    pub fn is_sub_phase(&self) -> bool {
 21→        self.sub_phase.is_some()
 22→    }
 23→
 24→    /// Get the full phase/sub-phase identifier.
 25→    pub fn full_phase_id(&self) -> String {
 26→        self.sub_phase.clone().unwrap_or_else(|| self.phase.clone())
 27→    }
 28→
 29→    /// Get the parent phase number for sub-phase entries.
 30→    pub fn parent_phase(&self) -> &str {
 31→        &self.phase
 32→    }
 33→}
 34→
 35→pub struct StateManager {
 36→    state_file: std::path::PathBuf,
 37→}
 38→
 39→impl StateManager {
 40→    pub fn new(state_file: std::path::PathBuf) -> Self {
 41→        Self { state_file }
 42→    }
 43→
 44→    /// Save a phase state entry (legacy format, backward compatible).
 45→    pub fn save(&self, phase: &str, iteration: u32, status: &str) -> Result<()> {
 46→        let entry = format!(
 47→            "{}|{}|{}|{}\n",
 48→            phase,
 49→            iteration,
 50→            status,
 51→            Utc::now().to_rfc3339()
 52→        );
 53→
 54→        fs::OpenOptions::new()
 55→            .create(true)
 56→            .append(true)
 57→            .open(&self.state_file)
 58→            .context("Failed to open state file")?
 59→            .write_all(entry.as_bytes())
 60→            .context("Failed to write state entry")?;
 61→
 62→        Ok(())
 63→    }
 64→
 65→    /// Save a sub-phase state entry with parent phase reference.
 66→    /// Format: phase|sub_phase|iteration|status|timestamp
 67→    pub fn save_sub_phase(
 68→        &self,
 69→        parent_phase: &str,
 70→        sub_phase: &str,
 71→        iteration: u32,
 72→        status: &str,
 73→    ) -> Result<()> {
 74→        let entry = format!(
 75→            "{}|{}|{}|{}|{}\n",
 76→            parent_phase,
 77→            sub_phase,
 78→            iteration,
 79→            status,
 80→            Utc::now().to_rfc3339()
 81→        );
 82→
 83→        fs::OpenOptions::new()
 84→            .create(true)
 85→            .append(true)
 86→            .open(&self.state_file)
 87→            .context("Failed to open state file")?
 88→            .write_all(entry.as_bytes())
 89→            .context("Failed to write sub-phase state entry")?;
 90→
 91→        Ok(())
 92→    }
 93→
 94→    /// Get the last completed top-level phase (not sub-phases).
 95→    pub fn get_last_completed_phase(&self) -> Option<String> {
 96→        if !self.state_file.exists() {
 97→            return None;
 98→        }
 99→
100→        let content = fs::read_to_string(&self.state_file).ok()?;
101→
102→        content
103→            .lines()
104→            .rfind(|line| {
105→                let parts: Vec<&str> = line.split('|').collect();
106→                // Old format has 4 parts, new sub-phase format has 5 parts
107→                // Only consider old format (top-level phases) for this query
108→                parts.len() == 4 && line.contains("|completed|")
109→            })
110→            .and_then(|line| line.split('|').next())
111→            .map(|s| s.to_string())
112→    }
113→
114→    /// Get the last completed phase or sub-phase.
115→    pub fn get_last_completed_any(&self) -> Option<String> {
116→        if !self.state_file.exists() {
117→            return None;
118→        }
119→
120→        let content = fs::read_to_string(&self.state_file).ok()?;
121→
122→        content
123→            .lines()
124→            .rfind(|line| line.contains("|completed|"))
125→            .and_then(|line| {
126→                let parts: Vec<&str> = line.split('|').collect();
127→                if parts.len() == 5 {
128→                    // Sub-phase format: phase|sub_phase|iteration|status|timestamp
129→                    Some(parts[1].to_string()) // Return sub-phase number
130→                } else if parts.len() >= 4 {
131→                    // Old format: phase|iteration|status|timestamp
132→                    Some(parts[0].to_string())
133→                } else {
134→                    None
135→                }
136→            })
137→    }
138→
139→    /// Get all state entries including sub-phase entries.
140→    ///
141→    /// Lines that cannot be fully parsed (e.g. corrupt or partial writes) are
142→    /// silently skipped with a warning rather than being returned as bogus
143→    /// entries with iteration == 0.
144→    pub fn get_entries(&self) -> Result<Vec<StateEntry>> {
145→        if !self.state_file.exists() {
146→            return Ok(Vec::new());
147→        }
148→
149→        let content = fs::read_to_string(&self.state_file).context("Failed to read state file")?;
150→
151→        let entries: Vec<StateEntry> = content
152→            .lines()
153→            .filter_map(|line| {
154→                let parts: Vec<&str> = line.split('|').collect();
155→                if parts.len() == 5 {
156→                    // New sub-phase format: phase|sub_phase|iteration|status|timestamp
157→                    let iteration = match parts[2].parse::<u32>() {
158→                        Ok(n) => n,
159→                        Err(_) => {
160→                            eprintln!(
161→                                "state: skipping malformed sub-phase line (bad iteration): {line}"
162→                            );
163→                            return None;
164→                        }
165→                    };
166→                    Some(StateEntry {
167→                        phase: parts[0].to_string(),
168→                        sub_phase: Some(parts[1].to_string()),
169→                        iteration,
170→                        status: parts[3].to_string(),
171→                        timestamp: DateTime::parse_from_rfc3339(parts[4])
172→                            .ok()?
173→                            .with_timezone(&Utc),
174→                    })
175→                } else if parts.len() >= 4 {
176→                    // Old format: phase|iteration|status|timestamp
177→                    let iteration = match parts[1].parse::<u32>() {
178→                        Ok(n) => n,
179→                        Err(_) => {
180→                            eprintln!(
181→                                "state: skipping malformed entry line (bad iteration): {line}"
182→                            );
183→                            return None;
184→                        }
185→                    };
186→                    Some(StateEntry {
187→                        phase: parts[0].to_string(),
188→                        sub_phase: None,
189→                        iteration,
190→                        status: parts[2].to_string(),
191→                        timestamp: DateTime::parse_from_rfc3339(parts[3])
192→                            .ok()?
193→                            .with_timezone(&Utc),
194→                    })
195→                } else {
196→                    None
197→                }
198→            })
199→            .collect();
200→
201→        Ok(entries)
202→    }
203→
204→    /// Get entries for a specific phase including its sub-phases.
205→    pub fn get_phase_entries(&self, phase: &str) -> Result<Vec<StateEntry>> {
206→        let entries = self.get_entries()?;
207→        Ok(entries.into_iter().filter(|e| e.phase == phase).collect())
208→    }
209→
210→    /// Get entries for a specific sub-phase.
211→    pub fn get_sub_phase_entries(&self, sub_phase: &str) -> Result<Vec<StateEntry>> {
212→        let entries = self.get_entries()?;
213→        Ok(entries
214→            .into_iter()
215→            .filter(|e| e.sub_phase.as_deref() == Some(sub_phase))
216→            .collect())
217→    }
218→
219→    /// Check if a phase has any sub-phase entries.
220→    pub fn has_sub_phase_entries(&self, phase: &str) -> Result<bool> {
221→        let entries = self.get_phase_entries(phase)?;
222→        Ok(entries.iter().any(|e| e.is_sub_phase()))
223→    }
224→
225→    /// Get all completed sub-phases for a parent phase.
226→    pub fn get_completed_sub_phases(&self, parent_phase: &str) -> Result<Vec<String>> {
227→        let entries = self.get_phase_entries(parent_phase)?;
228→        Ok(entries
229→            .into_iter()
230→            .filter(|e| e.is_sub_phase() && e.status == "completed")
231→            .filter_map(|e| e.sub_phase)
232→            .collect())
233→    }
234→
235→    /// Check if all sub-phases of a parent are complete.
236→    pub fn all_sub_phases_complete(
237→        &self,
238→        parent_phase: &str,
239→        expected_count: usize,
240→    ) -> Result<bool> {
241→        let completed = self.get_completed_sub_phases(parent_phase)?;
242→        Ok(completed.len() >= expected_count)
243→    }
244→
245→    pub fn reset(&self) -> Result<()> {
246→        if self.state_file.exists() {
247→            fs::remove_file(&self.state_file).context("Failed to remove state file")?;
248→        }
249→        Ok(())
250→    }
251→}
