117→impl IntoResponse for ApiError {
118→    fn into_response(self) -> Response {
119→        let (status, message) = match self {
120→            ApiError::NotFound(msg) => (StatusCode::NOT_FOUND, msg),
121→            ApiError::BadRequest(msg) => (StatusCode::BAD_REQUEST, msg),
122→            ApiError::Internal(msg) => (StatusCode::INTERNAL_SERVER_ERROR, msg),
123→        };
124→        (status, Json(serde_json::json!({"error": message}))).into_response()
125→    }
126→}
