224→/// Extract "owner/repo" from various GitHub URL formats.
225→fn parse_github_owner_repo(url: &str) -> Option<String> {
226→    let url = url.trim().trim_end_matches('/').trim_end_matches(".git");
227→    // Handle https://github.com/owner/repo and https://TOKEN@github.com/owner/repo
228→    if let Some(github_pos) = url.find("github.com/") {
229→        let rest = &url[github_pos + "github.com/".len()..];
230→        let parts: Vec<&str> = rest.splitn(3, '/').collect();
231→        if parts.len() >= 2 && !parts[0].is_empty() && !parts[1].is_empty() {
232→            return Some(format!("{}/{}", parts[0], parts[1]));
233→        }
234→    }
235→    if let Some(rest) = url.strip_prefix("git@github.com:") {
236→        let parts: Vec<&str> = rest.splitn(3, '/').collect();
237→        if parts.len() >= 2 {
238→            return Some(format!("{}/{}", parts[0], parts[1]));
239→        }
240→    }
241→    // Bare "owner/repo" format
242→    let parts: Vec<&str> = url.splitn(3, '/').collect();
243→    if parts.len() == 2 && !parts[0].contains(':') && !parts[0].contains('.') {
244→        return Some(format!("{}/{}", parts[0], parts[1]));
245→    }
246→    None
247→}
