 53→/// Serve embedded static files or fall back to index.html for SPA routing.
 54→async fn static_handler(req: Request<Body>) -> impl IntoResponse {
 55→    let path = req.uri().path().trim_start_matches('/');
 56→
 57→    // Try to serve the exact file
 58→    if !path.is_empty()
 59→        && let Some(content) = Assets::get(path)
 60→    {
 61→        let mime = mime_guess::from_path(path).first_or_octet_stream();
 62→        match Response::builder()
 63→            .header(header::CONTENT_TYPE, mime.as_ref())
 64→            .body(Body::from(content.data.to_vec()))
 65→        {
 66→            Ok(resp) => return resp.into_response(),
 67→            Err(_) => return StatusCode::INTERNAL_SERVER_ERROR.into_response(),
 68→        }
 69→    }
 70→
 71→    // Fall back to index.html for SPA client-side routing
 72→    match Assets::get("index.html") {
 73→        Some(content) => Html(String::from_utf8_lossy(&content.data).to_string()).into_response(),
 74→        None => (
 75→            StatusCode::NOT_FOUND,
 76→            "Frontend not found. Run 'npm run build' in ui/ directory.",
 77→        )
 78→            .into_response(),
 79→    }
 80→}
