588→    pub fn get_board(&self, project_id: i64) -> Result<BoardView> {
589→        let project = self
590→            .get_project(project_id)?
591→            .context("Project not found for board view")?;
592→
593→        let all_issues = self.list_issues(project_id)?;
594→
595→        let column_order = [
596→            IssueColumn::Backlog,
597→            IssueColumn::Ready,
598→            IssueColumn::InProgress,
599→            IssueColumn::InReview,
600→            IssueColumn::Done,
601→        ];
602→
603→        let mut columns = Vec::new();
604→        for col in &column_order {
605→            let mut col_issues: Vec<IssueWithStatus> = all_issues
606→                .iter()
607→                .filter(|i| i.column == *col)
608→                .map(|i| IssueWithStatus {
609→                    issue: i.clone(),
610→                    active_run: None,
611→                })
612→                .collect();
613→
614→            // Sort by position
615→            col_issues.sort_by_key(|iws| iws.issue.position);
616→
617→            // Find active runs for each issue
618→            for iws in &mut col_issues {
619→                let mut stmt = self.conn.prepare(
620→                    "SELECT id, issue_id, status, phase_count, current_phase, iteration, summary, error, branch_name, pr_url, team_id, has_team, started_at, completed_at
621→                     FROM pipeline_runs
622→                     WHERE issue_id = ?1 AND status IN ('queued', 'running')
623→                     ORDER BY id DESC LIMIT 1",
624→                )?;
625→                let mut rows = stmt.query_map(params![iws.issue.id], |row| {
626→                    Ok(PipelineRunRow {
627→                        id: row.get(0)?,
628→                        issue_id: row.get(1)?,
629→                        status: row.get(2)?,
630→                        phase_count: row.get(3)?,
631→                        current_phase: row.get(4)?,
632→                        iteration: row.get(5)?,
633→                        summary: row.get(6)?,
634→                        error: row.get(7)?,
635→                        branch_name: row.get(8)?,
636→                        pr_url: row.get(9)?,
637→                        team_id: row.get(10)?,
638→                        has_team: row.get(11)?,
639→                        started_at: row.get(12)?,
640→                        completed_at: row.get(13)?,
641→                    })
642→                })?;
643→                if let Some(row) = rows.next() {
644→                    let r = row.context("Failed to read pipeline_run row")?;
645→                    iws.active_run = Some(r.into_pipeline_run()?);
646→                }
647→            }
648→
649→            columns.push(ColumnView {
650→                name: col.clone(),
651→                issues: col_issues,
652→            });
653→        }
654→
655→        Ok(BoardView { project, columns })
656→    }
