 57→                sub_phase.number,
 58→                sub_phase.promise,
 59→                sub_phase.budget,
 60→                sub_phase.name,
 61→                console::style(format!("{:?}", sub_phase.status)).dim()
 62→            );
 63→        }
 64→    }
 65→    println!();
 66→
 67→    // Show total count including sub-phases
 68→    let total = pf.total_phase_count();
 69→    if total > pf.phases.len() {
 70→        println!(
 71→            "{} phases ({} top-level, {} sub-phases)",
 72→            total,
 73→            pf.phases.len(),
 74→            total - pf.phases.len()
 75→        );
