137→    // Show execution state
138→    let state_file = forge_dir.join("state");
139→    let state = StateManager::new(state_file);
140→
141→    println!();
142→    match state.get_entries() {
143→        Ok(entries) if !entries.is_empty() => {
144→            // Count completed phases (top-level only)
145→            let completed: std::collections::HashSet<_> = entries
146→                .iter()
147→                .filter(|e| e.status == "completed" && !e.is_sub_phase())
148→                .map(|e| &e.phase)
149→                .collect();
150→
151→            // Count completed sub-phases
152→            let completed_sub_phases: Vec<_> = entries
153→                .iter()
154→                .filter(|e| e.status == "completed" && e.is_sub_phase())
155→                .collect();
156→
157→            println!("Execution Progress:");
158→            println!("  Phases completed: {}", completed.len());
159→            if !completed_sub_phases.is_empty() {
160→                println!("  Sub-phases completed: {}", completed_sub_phases.len());
161→            }
162→
163→            if let Some(last) = state.get_last_completed_phase() {
164→                println!("  Last completed phase: {}", last);
165→            }
166→            if let Some(last_any) = state.get_last_completed_any()
167→                && last_any.contains('.')
168→            {
169→                println!("  Last completed (any): {}", last_any);
170→            }
171→
172→            println!();
173→            println!("Recent activity:");
174→            for entry in entries.iter().rev().take(5) {
175→                let phase_display = if let Some(ref sub) = entry.sub_phase {
176→                    format!("{} (sub-phase of {})", sub, entry.phase)
177→                } else {
178→                    format!("Phase {}", entry.phase)
179→                };
180→                println!(
181→                    "  {}: {} at iteration {} ({})",
182→                    phase_display,
183→                    entry.status,
184→                    entry.iteration,
185→                    entry.timestamp.format("%Y-%m-%d %H:%M:%S")
186→                );
187→            }
