  1→//! Context compaction status and manual trigger — `forge compact`.
  2→
  3→use anyhow::Result;
  4→
  5→use super::super::Cli;
  6→
  7→pub fn cmd_compact(
  8→    project_dir: &std::path::Path,
  9→    cli: &Cli,
 10→    phase: Option<&str>,
 11→    status_only: bool,
 12→) -> Result<()> {
 13→    use forge::compaction::{ContextTracker, DEFAULT_MODEL_WINDOW_CHARS};
 14→    use forge::forge_config::ForgeToml;
 15→    use forge::init::get_forge_dir;
 16→    use forge::orchestrator::StateManager;
 17→
 18→    let forge_dir = get_forge_dir(project_dir);
 19→    let state_file = forge_dir.join("state");
 20→    let state = StateManager::new(state_file);
 21→    let log_dir = forge_dir.join("logs");
 22→
 23→    // Determine which phase to work with
 24→    let phase_number = if let Some(p) = phase {
 25→        p.to_string()
 26→    } else {
 27→        // Get the most recent phase from state
 28→        state
 29→            .get_last_completed_phase()
 30→            .map(|p| {
 31→                // Get the next phase (current running phase)
 32→                format!("{:02}", p.parse::<u32>().unwrap_or(0) + 1)
 33→            })
 34→            .unwrap_or_else(|| "01".to_string())
 35→    };
 36→
 37→    println!();
 38→    println!("Context Compaction - Phase {}", phase_number);
 39→    println!("================================");
 40→    println!();
 41→
 42→    // Get context limit from config
 43→    let forge_toml = ForgeToml::load_or_default(&forge_dir)?;
 44→    let context_limit = cli
 45→        .context_limit
 46→        .clone()
 47→        .unwrap_or_else(|| forge_toml.defaults.context_limit.clone());
 48→
 49→    println!("Context limit: {}", context_limit);
 50→
 51→    // Calculate context usage from log files
 52→    let mut total_prompt_chars = 0usize;
 53→    let mut total_output_chars = 0usize;
 54→    let mut iteration_count = 0u32;
 55→
 56→    // Find all log files for this phase
 57→    if log_dir.exists() {
 58→        for entry in std::fs::read_dir(&log_dir)? {
 59→            let entry = entry?;
 60→            let file_name = entry.file_name();
 61→            let name = file_name.to_string_lossy();
 62→
 63→            if name.starts_with(&format!("phase-{}-iter-", phase_number)) {
 64→                if name.ends_with("-prompt.md") {
 65→                    if let Ok(content) = std::fs::read_to_string(entry.path()) {
 66→                        total_prompt_chars += content.len();
 67→                        iteration_count += 1;
 68→                    }
 69→                } else if name.ends_with("-output.log")
 70→                    && let Ok(content) = std::fs::read_to_string(entry.path())
 71→                {
 72→                    total_output_chars += content.len();
 73→                }
 74→            }
 75→        }
 76→    }
 77→
 78→    // Create tracker with current stats
 79→    let mut tracker = ContextTracker::new(&context_limit, DEFAULT_MODEL_WINDOW_CHARS);
 80→
 81→    // Simulate adding iterations (we don't have per-iteration breakdown from files)
 82→    if iteration_count > 0 {
 83→        let avg_prompt = total_prompt_chars / iteration_count as usize;
 84→        let avg_output = total_output_chars / iteration_count as usize;
 85→        for _ in 0..iteration_count {
 86→            tracker.add_iteration(avg_prompt, avg_output);
 87→        }
 88→    }
 89→
 90→    println!();
 91→    println!("Status:");
 92→    println!("  Iterations found: {}", iteration_count);
 93→    println!("  Total prompt chars: {}", total_prompt_chars);
 94→    println!("  Total output chars: {}", total_output_chars);
 95→    println!("  Total context used: {}", tracker.total_context_used());
 96→    println!("  Context limit: {} chars", tracker.effective_limit());
 97→    println!("  Usage: {:.1}%", tracker.usage_percentage());
 98→    println!("  Remaining budget: {} chars", tracker.remaining_budget());
 99→    println!();
100→
101→    if tracker.should_compact() {
102→        println!("Status: Compaction RECOMMENDED (approaching limit)");
103→    } else {
104→        println!("Status: Compaction not needed");
105→    }
106→
107→    if status_only {
108→        println!();
109→        println!(
110→            "Use 'forge compact --phase {}' to perform compaction.",
111→            phase_number
112→        );
113→        return Ok(());
114→    }
115→
116→    // Check if we need compaction
117→    if !tracker.should_compact() && iteration_count < 2 {
118→        println!();
119→        println!("No compaction needed at this time.");
120→        println!("  - Context usage is below threshold");
121→        println!("  - Need at least 2 iterations to compact");
122→        return Ok(());
123→    }
124→
125→    // Perform compaction by generating a summary
126→    println!();
127→    println!("Performing compaction...");
128→
129→    // For manual compaction, we generate a summary file that can be used
130→    let summary_file = log_dir.join(format!("phase-{}-compaction-summary.md", phase_number));
131→
132→    let summary_content = format!(
133→        r#"## CONTEXT COMPACTION SUMMARY
134→
135→Phase {} has been compacted to save context space.
136→
137→### Statistics
138→- Iterations compacted: {}
139→- Original context: {} chars
140→- This summary: ~{} chars
141→- Compression achieved: ~{:.1}%
142→
143→### Note
144→This is a manual compaction summary. The actual compaction occurs
145→automatically during orchestration when context approaches the limit.
146→
147→To leverage automatic compaction, the orchestrator will:
148→1. Track context usage across iterations
149→2. Summarize older iterations when approaching the limit
150→3. Inject the summary into subsequent prompts
151→
152→### Configuration
153→Set context_limit in forge.toml:
154→```toml
155→[defaults]
156→context_limit = "{}"
157→```
158→"#,
159→        phase_number,
160→        iteration_count,
161→        total_prompt_chars + total_output_chars,
162→        1000, // Approximate summary size
163→        if total_prompt_chars + total_output_chars > 0 {
164→            (1.0 - 1000.0 / (total_prompt_chars + total_output_chars) as f32) * 100.0
165→        } else {
166→            0.0
167→        },
168→        context_limit
169→    );
170→
171→    std::fs::write(&summary_file, &summary_content)?;
172→    println!("Summary written to: {}", summary_file.display());
173→    println!();
174→    println!("Compaction complete.");
175→
176→    Ok(())
177→}
