  1→//! Sequential phase orchestration — `forge run` and `forge phase <N>`.
  2→
  3→use anyhow::Result;
  4→use std::path::PathBuf;
  5→
  6→use super::super::Cli;
  7→
  8→pub fn check_run_prerequisites(project_dir: &std::path::Path) -> Result<()> {
  9→    use forge::init::{has_phases, is_initialized};
 10→
 11→    if !is_initialized(project_dir) {
 12→        anyhow::bail!(
 13→            "Project not initialized. Run 'forge init' first, then 'forge generate' to create phases."
 14→        );
 15→    }
 16→    if !has_phases(project_dir) {
 17→        anyhow::bail!(
 18→            "No phases found. Run 'forge generate' first to create phases from your spec."
 19→        );
 20→    }
 21→    Ok(())
 22→}
 23→
 24→pub async fn run_orchestrator(
 25→    cli: &Cli,
 26→    project_dir: PathBuf,
 27→    start_phase: Option<String>,
 28→) -> Result<()> {
 29→    use forge::audit::{AuditLogger, FileChangeSummary, PhaseAudit, PhaseOutcome, RunConfig};
 30→    use forge::compaction::{
 31→        CompactionManager, DEFAULT_MODEL_WINDOW_CHARS, extract_output_summary,
 32→    };
 33→    use forge::config::Config;
 34→    use forge::forge_config::{ForgeToml, PermissionMode};
 35→    use forge::gates::{
 36→        ApprovalGate, AutonomousGateStrategy, GateDecision, IterationDecision, ProgressTracker,
 37→    };
 38→    use forge::hooks::{HookAction, HookManager};
 39→    use forge::init::get_forge_dir;
 40→    use forge::orchestrator::{ClaudeRunner, IterationFeedback, PromptContext, StateManager};
 41→    use forge::phase::load_phases_or_default;
 42→    use forge::tracker::GitTracker;
 43→    use forge::ui::OrchestratorUI;
 44→
 45→    check_run_prerequisites(&project_dir)?;
 46→
 47→    let config = Config::new(
 48→        project_dir.clone(),
 49→        cli.verbose,
 50→        cli.auto_approve_threshold,
 51→        cli.spec_file.clone(),
 52→    )?;
 53→    config.ensure_directories()?;
 54→
 55→    // Initialize hook manager
 56→    let mut hook_manager = HookManager::new(&project_dir, cli.verbose)?;
 57→
 58→    // Merge hooks from forge.toml if it exists
 59→    let forge_dir = get_forge_dir(&project_dir);
 60→    if let Ok(toml) = ForgeToml::load_or_default(&forge_dir)
 61→        && !toml.hooks.definitions.is_empty()
 62→    {
 63→        hook_manager.merge_config(toml.hooks.into_hooks_config());
 64→    }
 65→
 66→    // Report hook count if any
 67→    let hook_count = hook_manager.hook_count();
 68→    if hook_count > 0 && cli.verbose {
 69→        println!("Loaded {} hook(s)", hook_count);
 70→    }
 71→
 72→    let state = StateManager::new(config.state_file.clone());
 73→    let tracker = GitTracker::new(&config.project_dir)?;
 74→    let runner = ClaudeRunner::new(config.clone());
 75→    let mut audit = AuditLogger::new(&config.audit_dir);
 76→    let mut gate = ApprovalGate::new(cli.auto_approve_threshold, cli.yes);
 77→
 78→    // Determine starting phase
 79→    let start = resolve_start_phase(
 80→        start_phase.as_deref(),
 81→        state.get_last_completed_phase().as_deref(),
 82→    );
 83→
 84→    // Load phases from phases.json if it exists, otherwise use defaults
 85→    let all_phases = load_phases_or_default(Some(&config.phases_file))?;
 86→
 87→    // Apply permission modes from config to each phase
 88→    let forge_toml = ForgeToml::load_or_default(&forge_dir)?;
 89→    let phases: Vec<_> = all_phases
 90→        .into_iter()
 91→        .filter(|p| p.number.as_str() >= start.as_str())
 92→        .map(|mut p| {
 93→            // Get phase settings from config (includes pattern-matched overrides)
 94→            let settings = forge_toml.phase_settings(&p.name);
 95→            // Apply permission mode from config if phase doesn't have one explicitly set
 96→            // (phases.json can override with explicit permission_mode)
 97→            if p.permission_mode == PermissionMode::Standard {
 98→                p.permission_mode = settings.permission_mode;
 99→            }
100→            // Budget is not overridden from config — phases.json is the primary source.
101→            p
102→        })
103→        .collect();
104→    // Create autonomous gate strategy if enabled (config or CLI flag)
105→    let autonomy_enabled = forge_toml.autonomy.enabled || cli.autonomous;
106→    let mut autonomous_strategy = if autonomy_enabled {
107→        Some(AutonomousGateStrategy::new(
108→            forge_toml.autonomy.stale_iterations_before_pivot,
109→            forge_toml.autonomy.pivot_prompt.clone(),
110→        ))
111→    } else {
112→        None
113→    };
114→
115→    let ui = std::sync::Arc::new(OrchestratorUI::new(phases.len() as u64, cli.verbose));
116→
117→    // Start audit run
118→    audit.start_run(RunConfig {
119→        auto_approve_threshold: cli.auto_approve_threshold,
120→        skip_permissions: config.skip_permissions,
121→        verbose: cli.verbose,
122→        spec_file: config.spec_file.clone(),
123→        project_dir: config.project_dir.clone(),
124→    })?;
125→
126→    let mut previous_changes: Option<FileChangeSummary> = None;
127→
128→    for phase in phases {
129→        // Run OnApproval hooks first (can auto-approve/reject)
130→        let approval_result = hook_manager
131→            .run_on_approval(&phase, previous_changes.as_ref())
132→            .await?;
133→
134→        let decision = match approval_result.action {
135→            HookAction::Approve => {
136→                if cli.verbose {
137→                    println!(
138→                        "  {} (hook auto-approved)",
139→                        console::style("Auto-approved").dim()
140→                    );
141→                }
142→                GateDecision::Approved
143→            }
144→            HookAction::Reject => {
145→                if let Some(msg) = &approval_result.message {
146→                    println!("  Hook rejected: {}", msg);
147→                }
148→                GateDecision::Rejected
149→            }
150→            HookAction::Block => {
151→                if let Some(msg) = &approval_result.message {
152→                    println!("  Hook blocked: {}", msg);
153→                }
154→                audit.finish_run()?;
155→                return Ok(());
156→            }
157→            _ => {
158→                if autonomous_strategy.is_some() {
159→                    // Autonomous mode: auto-approve all phases
160→                    GateDecision::Approved
161→                } else {
162→                    // Interactive: use normal approval gate
163→                    gate.check_phase(&phase, previous_changes.as_ref(), &ui)?
164→                }
165→            }
166→        };
167→
168→        match decision {
169→            GateDecision::Aborted => {
170→                println!("Orchestrator aborted by user");
171→                audit.finish_run()?;
172→                return Ok(());
173→            }
174→            GateDecision::Rejected => {
175→                println!("Phase {} skipped", phase.number);
176→                continue;
177→            }
178→            GateDecision::Approved | GateDecision::ApprovedAll => {}
179→        }
180→
181→        // Run PrePhase hooks
182→        let pre_phase_result = hook_manager
183→            .run_pre_phase(&phase, previous_changes.as_ref())
184→            .await?;
185→
186→        match pre_phase_result.action {
187→            HookAction::Block => {
188→                if let Some(msg) = &pre_phase_result.message {
189→                    println!("  PrePhase hook blocked: {}", msg);
190→                }
191→                audit.finish_run()?;
192→                return Ok(());
193→            }
194→            HookAction::Skip => {
195→                if let Some(msg) = &pre_phase_result.message {
196→                    println!("  PrePhase hook skipped phase: {}", msg);
197→                }
198→                continue;
199→            }
200→            _ => {}
201→        }
202→
203→        ui.start_phase(&phase.number, &phase.name);
204→        state.save(&phase.number, 0, "started")?;
205→
206→        let mut phase_audit = PhaseAudit::new(&phase.number, &phase.name, &phase.promise);
207→
208→        // Take git snapshot before phase
209→        let snapshot_sha = tracker.snapshot_before(&phase.number)?;
210→
211→        // Initialize progress tracker for autonomous mode
212→        let mut progress_tracker = ProgressTracker::new();
213→
214→        // Initialize compaction manager for this phase
215→        let context_limit = cli
216→            .context_limit
217→            .clone()
218→            .unwrap_or_else(|| forge_toml.phase_settings(&phase.name).context_limit);
219→        let mut compaction_manager = CompactionManager::new(
220→            &phase.number,
221→            &phase.name,
222→            &phase.promise,
223→            &context_limit,
224→            DEFAULT_MODEL_WINDOW_CHARS,
225→        );
226→
227→        // Track current prompt context (compaction summary if any)
228→        let mut current_prompt_context: Option<PromptContext> = None;
229→
230→        // Session continuity: track active session ID for --resume across iterations
231→        let mut active_session_id: Option<String> = None;
232→        // Iteration feedback: track feedback to inject via --append-system-prompt
233→        let mut previous_feedback: Option<String> = None;
234→
235→        // Check if session continuity and iteration feedback are enabled
236→        let session_continuity_enabled = forge_toml.claude.session_continuity;
237→        let iteration_feedback_enabled = forge_toml.claude.iteration_feedback;
238→
239→        let mut completed = false;
240→        let mut phase_aborted = false;
241→        // Accumulators for budget-exhaustion diagnostics
242→        let mut total_blockers_raised: usize = 0;
243→        let mut any_progress_signaled = false;
244→        let mut total_pivots: usize = 0;
245→        for iter in 1..=phase.budget {
246→            // === AUTONOMOUS MODE: Check progress before continuing ===
247→            if phase.permission_mode == PermissionMode::Autonomous && iter > 1 {
248→                if let Some(ref mut auto_strategy) = autonomous_strategy {
249→                    let pivot_was_issued = auto_strategy.stale_handler.pivot_issued;
250→                    match auto_strategy.check_stale_progress(&phase, &mut progress_tracker) {
251→                        IterationDecision::StopPhase => {
252→                            println!("  Phase stopped: no progress after pivot");
253→                            break;
254→                        }
255→                        IterationDecision::Continue
256→                            if !pivot_was_issued && auto_strategy.stale_handler.pivot_issued =>
257→                        {
258→                            // Pivot was just issued — inject prompt
259→                            previous_feedback = Some(auto_strategy.pivot_prompt().to_string());
260→                        }
261→                        _ => {}
262→                    }
263→                } else if !gate.check_autonomous_progress(&progress_tracker) {
264→                    // Interactive fallback
265→                    match gate.prompt_no_progress()? {
266→                        IterationDecision::Continue => {
267→                            progress_tracker.stale_iterations = 0;
268→                        }
269→                        IterationDecision::StopPhase => {
270→                            println!("  Phase stopped due to no progress");
271→                            break;
272→                        }
273→                        IterationDecision::Abort => {
274→                            println!("  Orchestrator aborted by user");
275→                            phase_aborted = true;
276→                            break;
277→                        }
278→                        IterationDecision::Skip => {
279→                            continue;
280→                        }
281→                    }
282→                }
283→            }
284→
285→            // Run PreIteration hooks
286→            let pre_iter_result = hook_manager.run_pre_iteration(&phase, iter).await?;
287→
288→            match pre_iter_result.action {
289→                HookAction::Block => {
290→                    if let Some(msg) = &pre_iter_result.message {
291→                        println!("  PreIteration hook blocked: {}", msg);
292→                    }
293→                    break;
294→                }
295→                HookAction::Skip => {
296→                    if let Some(msg) = &pre_iter_result.message {
297→                        println!("  PreIteration hook skipped iteration: {}", msg);
298→                    }
299→                    continue;
300→                }
301→                _ => {}
302→            }
303→
304→            ui.start_iteration(iter, phase.budget);
305→
306→            // Check if compaction is needed before this iteration
307→            if let Some(summary_text) = compaction_manager.compact_if_needed() {
308→                if cli.verbose {
309→                    println!("  Context compacted: {}", compaction_manager.status());
310→                }
311→                // Record compaction in audit
312→                if let Some(compaction) = compaction_manager.last_compaction() {
313→                    phase_audit.add_compaction_event(
314→                        compaction.iterations_summarized,
315→                        compaction.original_chars,
316→                        compaction.summary_chars,
317→                    );
318→                }
319→                current_prompt_context = Some(PromptContext::with_compaction(summary_text));
320→                // Reset session on compaction — the compacted context replaces history
321→                active_session_id = None;
322→                previous_feedback = None;
323→            }
324→
325→            // Run iteration with optional compaction context, session resumption, and feedback
326→            let result = runner
327→                .run_iteration_with_context(
328→                    &phase,
329→                    iter,
330→                    Some(ui.clone()),
331→                    current_prompt_context.as_ref(),
332→                    if session_continuity_enabled {
333→                        active_session_id.as_deref()
334→                    } else {
335→                        None
336→                    },
337→                    if iteration_feedback_enabled {
338→                        previous_feedback.as_deref()
339→                    } else {
340→                        None
341→                    },
342→                )
343→                .await?;
344→
345→            // Compute changes
346→            let changes = tracker.compute_changes(&snapshot_sha)?;
347→            ui.update_files(&changes);
348→
349→            // === READONLY MODE: Validate no modifications ===
350→            if phase.permission_mode == PermissionMode::Readonly
351→                && let Err(e) = gate.validate_readonly_changes(&phase, &changes)
352→            {
353→                println!("  {} {}", console::style("Error:").red().bold(), e);
354→                ui.phase_failed(&phase.number, "readonly mode violation");
355→                phase_audit.finish(
356→                    PhaseOutcome::Error {
357→                        message: e.to_string(),
358→                    },
359→                    changes.clone(),
360→                );
361→                break;
362→            }
363→
364→            // Show individual file changes
365→            for path in &changes.files_added {
366→                ui.show_file_change(path, forge::audit::ChangeType::Added);
367→            }
368→            for path in &changes.files_modified {
369→                ui.show_file_change(path, forge::audit::ChangeType::Modified);
370→            }
371→
372→            // Accumulate cross-iteration signal diagnostics for budget-exhaustion reporting
373→            total_blockers_raised += result.signals.blockers.len();
374→            if result.signals.latest_progress().is_some() {
375→                any_progress_signaled = true;
376→            }
377→            total_pivots += result.signals.pivots.len();
378→
379→            // Update progress tracker for autonomous mode
380→            let progress_pct = result.signals.latest_progress();
381→            progress_tracker.update(&changes, progress_pct);
382→
383→            // Capture session ID for --resume in next iteration
384→            if let Some(ref sid) = result.session.session_id {
385→                active_session_id = Some(sid.clone());
386→            }
387→
388→            // Build iteration feedback for next iteration
389→            previous_feedback = IterationFeedback::new()
390→                .with_iteration_status(iter, phase.budget, result.promise_found)
391→                .with_git_changes(&changes)
392→                .with_signals(&result.signals)
393→                .build();
394→
395→            // Record iteration in compaction manager
396→            let output_summary = extract_output_summary(&result.output, 100);
397→            compaction_manager.record_iteration(
398→                iter,
399→                result.session.prompt_chars,
400→                result.session.output_chars,
401→                &changes,
402→                &result.signals,
403→                &output_summary,
404→            );
405→
406→            // Show context status in verbose mode
407→            if cli.verbose && iter > 1 {
408→                println!("  {}", compaction_manager.status());
409→            }
410→
411→            // Run PostIteration hooks with signals
412→            let post_iter_result = hook_manager
413→                .run_post_iteration_with_signals(
414→                    &phase,
415→                    iter,
416→                    &changes,
417→                    result.promise_found,
418→                    Some(&result.output),
419→                    &result.signals,
420→                )
421→                .await?;
422→
423→            // Handle blockers - pause and prompt user if there are unacknowledged blockers
424→            if result.signals.has_unacknowledged_blockers() {
425→                let blockers = result.signals.unacknowledged_blockers();
426→                for blocker in &blockers {
427→                    ui.show_blocker(&blocker.description);
428→                }
429→
430→                // Auto-continue if --yes flag is set
431→                let continue_anyway = if cli.yes {
432→                    println!(
433→                        "  {} {} blocker(s) detected, auto-continuing (--yes flag)",
434→                        console::style("⚠").yellow(),
435→                        blockers.len()
436→                    );
437→                    true
438→                } else {
439→                    // Prompt user about blockers
440→                    use dialoguer::Confirm;
441→                    match Confirm::new()
442→                        .with_prompt(format!(
443→                            "{} blocker(s) detected. Continue anyway?",
444→                            blockers.len()
445→                        ))
446→                        .default(false)
447→                        .interact()
448→                    {
449→                        Ok(answer) => answer,
450→                        Err(e) => {
451→                            eprintln!(
452→                                "Warning: Could not display blocker confirmation dialog: {}. \
453→                                 Stopping. Re-run with --yes to auto-continue past blockers.",
454→                                e
455→                            );
456→                            false
457→                        }
458→                    }
459→                };
460→
461→                if !continue_anyway {
462→                    ui.phase_failed(&phase.number, "User stopped due to blockers");
463→                    phase_audit.finish(PhaseOutcome::UserAborted, changes.clone());
464→                    break;
465→                }
466→            }
467→
468→            // PostIteration hook can override promise detection
469→            let should_complete = match post_iter_result.action {
470→                HookAction::Block => {
471→                    if let Some(msg) = &post_iter_result.message {
472→                        println!("  PostIteration hook blocked: {}", msg);
473→                    }
474→                    false
475→                }
476→                _ => result.promise_found,
477→            };
478→
479→            if should_complete {
480→                ui.iteration_success(iter);
481→                phase_audit.finish(PhaseOutcome::Completed { iteration: iter }, changes.clone());
482→                state.save(&phase.number, iter, "completed")?;
483→                previous_changes = Some(changes);
484→                completed = true;
485→                break;
486→            } else {
487→                // Show progress if available
488→                if let Some(pct) = result.signals.latest_progress() {
489→                    ui.iteration_bar_message(iter, phase.budget, &format!("{}% done", pct));
490→                }
491→                ui.iteration_continue(iter);
492→            }
493→
494→            tokio::time::sleep(tokio::time::Duration::from_secs(2)).await;
495→        }
496→
497→        // Handle phase abort (exit orchestrator entirely)
498→        if phase_aborted {
499→            audit.finish_run()?;
500→            return Ok(());
501→        }
502→
503→        if !completed {
504→            let changes = tracker.compute_changes(&snapshot_sha)?;
505→
506→            // Run OnFailure hooks
507→            let failure_result = hook_manager
508→                .run_on_failure(&phase, phase.budget, &changes)
509→                .await?;
510→
511→            if let Some(msg) = &failure_result.message {
512→                println!("  OnFailure hook: {}", msg);
513→            }
514→
515→            phase_audit.finish(PhaseOutcome::MaxIterationsReached, changes);
516→            state.save(&phase.number, phase.budget, "max_iterations")?;
517→            ui.phase_failed(&phase.number, "max iterations reached");
518→
519→            // Actionable budget-exhaustion summary
520→            println!();
521→            println!(
522→                "  {} Phase '{}' exhausted its budget of {} iteration(s) without emitting the promise tag '{}'.",
523→                console::style("Budget exhausted:").red().bold(),
524→                phase.name,
525→                phase.budget,
526→                phase.promise,
527→            );
528→            // Summarize what signals were observed across the whole phase
529→            let progress_note = if any_progress_signaled {
530→                "progress was signaled at least once".to_string()
531→            } else {
532→                "no <progress> signals were ever emitted".to_string()
533→            };
534→            let blockers_note = blocker_note(total_blockers_raised);
535→            let pivots_note = pivot_note(total_pivots);
536→            println!("  Summary: {progress_note}; {blockers_note}; {pivots_note}.");
537→            println!(
538→                "  Tip: Verify the promise tag in your phases config matches exactly \
539→                (case-sensitive). Run 'forge audit --last' to inspect Claude's raw output."
540→            );
541→            println!(
542→                "  Tip: Use <progress>N%</progress> and <blocker>reason</blocker> tags \
543→                in your phase prompt to help diagnose stuck phases."
544→            );
545→        } else {
546→            // Run PostPhase hooks
547→            let post_phase_result = hook_manager
548→                .run_post_phase(
549→                    &phase,
550→                    phase.budget,
551→                    previous_changes
552→                        .as_ref()
553→                        .unwrap_or(&FileChangeSummary::default()),
554→                    true,
555→                )
556→                .await?;
557→
558→            if let Some(msg) = &post_phase_result.message
559→                && cli.verbose
560→            {
561→                println!("  PostPhase hook: {}", msg);
562→            }
563→
564→            ui.phase_complete(&phase.number);
565→        }
566→
567→        audit.add_phase(phase_audit)?;
568→
569→        tokio::time::sleep(tokio::time::Duration::from_secs(5)).await;
570→    }
571→
572→    let run_file = audit.finish_run()?;
573→    println!("Audit log saved to: {}", run_file.display());
574→
575→    Ok(())
576→}
