578→/// Build a human-readable note for the number of blockers raised during a phase.
579→///
580→/// Returns a string like "3 blockers raised" or "no blockers raised".
581→/// This is pure logic that can be unit-tested without external processes.
582→pub fn blocker_note(total_blockers_raised: usize) -> String {
583→    if total_blockers_raised > 0 {
584→        format!(
585→            "{} blocker{} raised",
586→            total_blockers_raised,
587→            if total_blockers_raised == 1 { "" } else { "s" }
588→        )
589→    } else {
590→        "no blockers raised".to_string()
591→    }
592→}
593→
594→/// Build a human-readable note for the number of pivots signaled during a phase.
595→///
596→/// Returns a string like "2 pivots signaled" or "no pivots signaled".
597→/// This is pure logic that can be unit-tested without external processes.
598→pub fn pivot_note(total_pivots: usize) -> String {
599→    if total_pivots > 0 {
600→        format!(
601→            "{} pivot{} signaled",
602→            total_pivots,
603→            if total_pivots == 1 { "" } else { "s" }
604→        )
605→    } else {
606→        "no pivots signaled".to_string()
607→    }
608→}
609→
610→/// Resolve the phase start string from an optional user-supplied value and
611→/// last-completed state.
612→///
613→/// - If `start_phase` is `Some(s)`, that string is returned directly.
614→/// - Otherwise the next phase after `last_completed` is returned (zero-padded
615→///   to two digits), falling back to `"01"` when nothing has been completed.
616→///
617→/// This is pure logic that can be unit-tested without external processes.
618→pub fn resolve_start_phase(start_phase: Option<&str>, last_completed: Option<&str>) -> String {
619→    start_phase.map(|s| s.to_string()).unwrap_or_else(|| {
620→        last_completed
621→            .map(|p| format!("{:02}", p.parse::<u32>().unwrap_or(0) + 1))
622→            .unwrap_or_else(|| "01".to_string())
623→    })
624→}
