626→pub async fn run_single_phase(cli: &Cli, project_dir: PathBuf, phase_num: &str) -> Result<()> {
627→    use forge::init::get_forge_dir;
628→    use forge::phase::PhasesFile;
629→
630→    check_run_prerequisites(&project_dir)?;
631→
632→    // Load phases from phases.json
633→    let forge_dir = get_forge_dir(&project_dir);
634→    let phases_file = forge_dir.join("phases.json");
635→    let pf = PhasesFile::load(&phases_file)?;
636→
637→    let phase = pf
638→        .phases
639→        .into_iter()
640→        .find(|p| p.number == phase_num)
641→        .ok_or_else(|| anyhow::anyhow!("Unknown phase: {}", phase_num))?;
642→
643→    run_orchestrator(cli, project_dir, Some(phase.number)).await
644→}
