  7→/// Runtime configuration for Forge.
  8→///
  9→/// This struct bridges the unified ForgeConfig with the runtime needs of
 10→/// the orchestrator. It handles spec file discovery and provides convenient
 11→/// access to all configuration values.
 12→#[derive(Debug, Clone)]
 13→pub struct Config {
 14→    pub project_dir: PathBuf,
 15→    pub spec_file: PathBuf,
 16→    pub phases_file: PathBuf,
 17→    pub audit_dir: PathBuf,
 18→    pub log_dir: PathBuf,
 19→    pub state_file: PathBuf,
 20→    pub claude_cmd: String,
 21→    pub skip_permissions: bool,
 22→    pub verbose: bool,
 23→    pub auto_approve_threshold: usize,
 24→    /// The underlying unified configuration
 25→    forge_config: Option<ForgeConfig>,
 26→}
 27→
 28→impl Config {
 29→    /// Create a new Config with the specified parameters.
 30→    ///
 31→    /// This constructor maintains backward compatibility while internally
 32→    /// using ForgeConfig for unified settings.
 33→    pub fn new(
 34→        project_dir: PathBuf,
 35→        verbose: bool,
 36→        auto_approve_threshold: usize,
 37→        spec_file: Option<PathBuf>,
 38→    ) -> Result<Self> {
 39→        let project_dir = project_dir
 40→            .canonicalize()
 41→            .context("Failed to resolve project directory")?;
 42→
 43→        // Load unified configuration
 44→        let forge_config = ForgeConfig::with_cli_args(
 45→            project_dir.clone(),
 46→            verbose,
 47→            false,
 48→            Some(auto_approve_threshold),
 49→        )
 50→        .ok();
 51→
 52→        let spec_file = match spec_file {
 53→            Some(path) => path
 54→                .canonicalize()
 55→                .context("Failed to resolve spec file path")?,
 56→            None => Self::find_spec_file(&project_dir)?,
 57→        };
 58→        let forge_dir = project_dir.join(".forge");
 59→        let phases_file = forge_dir.join("phases.json");
 60→        let audit_dir = forge_dir.join("audit");
 61→        let log_dir = forge_dir.join("logs");
 62→        let state_file = forge_dir.join("state");
 63→
 64→        // Get values from ForgeConfig if available, otherwise fall back to env/defaults
 65→        let (claude_cmd, skip_permissions) = if let Some(ref fc) = forge_config {
 66→            (fc.claude_cmd(), fc.skip_permissions())
 67→        } else {
 68→            let claude_cmd = std::env::var("CLAUDE_CMD").unwrap_or_else(|_| "claude".to_string());
 69→            let skip_permissions = std::env::var("SKIP_PERMISSIONS")
 70→                .map(|v| v != "false")
 71→                .unwrap_or(true);
 72→            (claude_cmd, skip_permissions)
 73→        };
 74→
 75→        Ok(Self {
 76→            project_dir,
 77→            spec_file,
 78→            phases_file,
 79→            audit_dir,
 80→            log_dir,
 81→            state_file,
 82→            claude_cmd,
 83→            skip_permissions,
 84→            verbose,
 85→            auto_approve_threshold,
 86→            forge_config,
 87→        })
 88→    }
 89→
 90→    /// Get the underlying ForgeConfig if available.
 91→    pub fn forge_config(&self) -> Option<&ForgeConfig> {
 92→        self.forge_config.as_ref()
 93→    }
 94→
 95→    pub fn ensure_directories(&self) -> Result<()> {
 96→        std::fs::create_dir_all(&self.audit_dir).context("Failed to create audit directory")?;
 97→        std::fs::create_dir_all(&self.log_dir).context("Failed to create log directory")?;
 98→        std::fs::create_dir_all(self.audit_dir.join("runs"))
 99→            .context("Failed to create runs directory")?;
100→        std::fs::create_dir_all(self.audit_dir.join("snapshots"))
101→            .context("Failed to create snapshots directory")?;
102→        Ok(())
103→    }
104→
105→    pub fn claude_flags(&self) -> Vec<String> {
106→        let mut flags = Vec::new();
107→        if self.skip_permissions {
108→            flags.push("--dangerously-skip-permissions".to_string());
109→        }
110→        flags.push("--print".to_string());
111→        flags.push("--output-format".to_string());
112→        flags.push("stream-json".to_string());
113→        flags.push("--verbose".to_string());
114→        flags
115→    }
116→
117→    /// Find a spec file, checking .forge/spec.md first, then docs/plans/*spec*.md
118→    /// Returns the most recently modified spec file if multiple are found in docs/plans/
119→    fn find_spec_file(project_dir: &Path) -> Result<PathBuf> {
120→        // First, check .forge/spec.md (preferred location)
121→        let forge_spec = project_dir.join(".forge/spec.md");
122→        if forge_spec.exists() {
123→            return Ok(forge_spec);
124→        }
125→
126→        // Fall back to docs/plans/*spec*.md for backward compatibility
127→        let pattern = project_dir
128→            .join("docs/plans/*spec*.md")
129→            .to_string_lossy()
130→            .to_string();
131→
132→        let mut spec_files: Vec<PathBuf> = glob(&pattern)
133→            .context("Failed to read glob pattern")?
134→            .filter_map(|entry| entry.ok())
135→            .collect();
136→
137→        if spec_files.is_empty() {
138→            return Err(anyhow!(
139→                "No spec file found. Create .forge/spec.md or provide --spec-file"
140→            ));
141→        }
142→
143→        // Sort by modification time (most recent first)
144→        spec_files.sort_by(|a, b| {
145→            let a_time = a.metadata().and_then(|m| m.modified()).ok();
146→            let b_time = b.metadata().and_then(|m| m.modified()).ok();
147→            b_time.cmp(&a_time)
148→        });
149→
150→        Ok(spec_files.remove(0))
151→    }
152→}
