140→}
141→
142→/// Check if a spec file exists and has content.
143→///
144→/// Returns `true` if `.forge/spec.md` exists and is not empty.
145→pub fn has_spec(project_dir: &Path) -> bool {
146→    let spec_file = project_dir.join(FORGE_DIR).join("spec.md");
147→    if !spec_file.exists() {
148→        return false;
149→    }
150→    match std::fs::read_to_string(&spec_file) {
151→        Ok(content) => !content.trim().is_empty(),
152→        Err(_) => false,
153→    }
154→}
155→
156→/// Check if phases have been generated.
157→///
158→/// Returns `true` if `.forge/phases.json` exists and contains valid JSON.
159→pub fn has_phases(project_dir: &Path) -> bool {
160→    let phases_file = project_dir.join(FORGE_DIR).join("phases.json");
161→    if !phases_file.exists() {
162→        return false;
163→    }
164→    match std::fs::read_to_string(&phases_file) {
165→        Ok(content) => {
166→            if content.trim().is_empty() {
167→                return false;
168→            }
169→            // Try to parse as JSON to verify it's valid
170→            serde_json::from_str::<serde_json::Value>(&content).is_ok()
171→        }
172→        Err(_) => false,
173→    }
174→}
