 31→/// Phase type classification for pattern learning.
 32→///
 33→/// Classifies phases into categories to enable better budget prediction
 34→/// and pattern matching.
 35→#[derive(Debug, Clone, Copy, Serialize, Deserialize, PartialEq, Eq, Hash, Default)]
 36→#[serde(rename_all = "lowercase")]
 37→pub enum PhaseType {
 38→    /// Initial project setup (scaffolding, boilerplate, project structure)
 39→    Scaffold,
 40→    /// Core feature implementation (main functionality)
 41→    #[default]
 42→    Implement,
 43→    /// Test implementation (unit tests, integration tests)
 44→    Test,
 45→    /// Code improvements (refactoring, optimization)
 46→    Refactor,
 47→    /// Bug fixes and patches
 48→    Fix,
 49→}
 50→
 51→impl PhaseType {
 52→    /// Classify a phase based on its name.
 53→    ///
 54→    /// Uses keyword matching to determine the phase type.
 55→    pub fn classify(phase_name: &str) -> Self {
 56→        let name_lower = phase_name.to_lowercase();
 57→
 58→        // Check for scaffold-related keywords
 59→        if name_lower.contains("scaffold")
 60→            || name_lower.contains("setup")
 61→            || name_lower.contains("init")
 62→            || name_lower.contains("bootstrap")
 63→            || name_lower.contains("boilerplate")
 64→            || name_lower.contains("structure")
 65→            || name_lower.contains("skeleton")
 66→        {
 67→            return PhaseType::Scaffold;
 68→        }
 69→
 70→        // Check for test-related keywords
 71→        if name_lower.contains("test")
 72→            || name_lower.contains("spec")
 73→            || name_lower.contains("coverage")
 74→            || name_lower.contains("e2e")
 75→            || name_lower.contains("integration test")
 76→        {
 77→            return PhaseType::Test;
 78→        }
 79→
 80→        // Check for refactor-related keywords
 81→        if name_lower.contains("refactor")
 82→            || name_lower.contains("cleanup")
 83→            || name_lower.contains("optimize")
 84→            || name_lower.contains("improve")
 85→            || name_lower.contains("restructure")
 86→            || name_lower.contains("simplify")
 87→        {
 88→            return PhaseType::Refactor;
 89→        }
 90→
 91→        // Check for fix-related keywords
 92→        if name_lower.contains("fix")
 93→            || name_lower.contains("bug")
 94→            || name_lower.contains("patch")
 95→            || name_lower.contains("hotfix")
 96→            || name_lower.contains("repair")
 97→            || name_lower.contains("correct")
 98→        {
 99→            return PhaseType::Fix;
100→        }
101→
102→        // Default to implementation
103→        PhaseType::Implement
104→    }
105→
106→    /// Get a display string for the phase type.
107→    pub fn as_str(&self) -> &'static str {
108→        match self {
109→            PhaseType::Scaffold => "scaffold",
110→            PhaseType::Implement => "implement",
111→            PhaseType::Test => "test",
112→            PhaseType::Refactor => "refactor",
113→            PhaseType::Fix => "fix",
114→        }
115→    }
116→}
117→
118→impl std::fmt::Display for PhaseType {
119→    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
120→        write!(f, "{}", self.as_str())
121→    }
122→}
