124→/// Statistics for a single phase in a pattern.
125→#[derive(Debug, Clone, Serialize, Deserialize, PartialEq)]
126→pub struct PhaseStat {
127→    /// Name of the phase
128→    pub name: String,
129→    /// Promise tag for this phase
130→    pub promise: String,
131→    /// Actual number of iterations taken to complete
132→    pub actual_iterations: u32,
133→    /// Original budget allocated to this phase
134→    pub original_budget: u32,
135→    /// Classification of the phase type
136→    #[serde(default)]
137→    pub phase_type: PhaseType,
138→    /// Files modified during this phase (glob-like patterns)
139→    #[serde(default)]
140→    pub file_patterns: Vec<String>,
141→    /// Common errors encountered during this phase (if any)
142→    #[serde(default)]
143→    pub common_errors: Vec<String>,
144→}
145→
146→impl PhaseStat {
147→    /// Returns `true` when this phase used more iterations than its original budget.
148→    ///
149→    /// This is computed on-the-fly from `actual_iterations` and `original_budget`
150→    /// so it is always consistent with the underlying data.
151→    pub fn exceeded_budget(&self) -> bool {
152→        self.actual_iterations > self.original_budget
153→    }
154→}
155→
156→/// Aggregate statistics for a phase type across a pattern.
157→#[derive(Debug, Clone, Serialize, Deserialize, PartialEq, Default)]
158→pub struct PhaseTypeStats {
159→    /// Number of phases of this type
160→    pub count: u32,
161→    /// Average iterations to complete phases of this type
162→    pub avg_iterations: f64,
163→    /// Minimum iterations observed
164→    pub min_iterations: u32,
165→    /// Maximum iterations observed
166→    pub max_iterations: u32,
167→    /// Average budget allocated to this type
168→    pub avg_budget: f64,
169→    /// Success rate (% within budget) for this type
170→    pub success_rate: f64,
171→}
172→
173→impl PhaseTypeStats {
174→    /// Create stats from a set of phase stats.
175→    pub fn from_phases(phases: &[&PhaseStat]) -> Self {
176→        if phases.is_empty() {
177→            return Self::default();
178→        }
179→
180→        let count = phases.len() as u32;
181→        let total_iterations: u32 = phases.iter().map(|p| p.actual_iterations).sum();
182→        let total_budget: u32 = phases.iter().map(|p| p.original_budget).sum();
183→        let min_iterations = phases
184→            .iter()
185→            .map(|p| p.actual_iterations)
186→            .min()
187→            .unwrap_or(0);
188→        let max_iterations = phases
189→            .iter()
190→            .map(|p| p.actual_iterations)
191→            .max()
192→            .unwrap_or(0);
193→        let within_budget = phases
194→            .iter()
195→            .filter(|p| p.actual_iterations <= p.original_budget)
196→            .count();
197→
198→        Self {
199→            count,
200→            avg_iterations: total_iterations as f64 / count as f64,
201→            min_iterations,
202→            max_iterations,
203→            avg_budget: total_budget as f64 / count as f64,
204→            success_rate: within_budget as f64 / count as f64,
205→        }
206→    }
207→}
