209→/// A learned pattern from a completed project.
210→#[derive(Debug, Clone, Serialize, Deserialize, PartialEq)]
211→pub struct Pattern {
212→    /// Name of the pattern (usually project name)
213→    pub name: String,
214→    /// When the pattern was created
215→    pub created_at: DateTime<Utc>,
216→    /// Tags describing the project (e.g., ["rust", "api", "auth"])
217→    pub tags: Vec<String>,
