219→    pub spec_summary: String,
220→    /// Statistics for each phase
221→    pub phase_stats: Vec<PhaseStat>,
222→    /// Total number of phases in the project
223→    pub total_phases: usize,
224→    /// Success rate (completed phases / total phases)
225→    pub success_rate: f64,
226→    /// Aggregate statistics by phase type
227→    #[serde(default)]
228→    pub type_stats: HashMap<String, PhaseTypeStats>,
229→    /// Common file patterns across the project (deduplicated)
230→    #[serde(default)]
231→    pub common_file_patterns: Vec<String>,
232→}
