234→impl Pattern {
235→    /// Create a new empty pattern with the given name.
236→    pub fn new(name: &str) -> Self {
237→        Self {
238→            name: name.to_string(),
239→            created_at: Utc::now(),
240→            tags: Vec::new(),
241→            spec_summary: String::new(),
242→            phase_stats: Vec::new(),
