250→    /// Compute aggregate statistics by phase type from phase_stats.
251→    pub fn compute_type_stats(&mut self) {
252→        let mut by_type: HashMap<PhaseType, Vec<&PhaseStat>> = HashMap::new();
253→
254→        for stat in &self.phase_stats {
255→            by_type.entry(stat.phase_type).or_default().push(stat);
