258→        self.type_stats.clear();
259→        for (phase_type, phases) in by_type {
260→            let stats = PhaseTypeStats::from_phases(&phases);
261→            self.type_stats
262→                .insert(phase_type.as_str().to_string(), stats);
263→        }
264→    }
