672→    } else {
673→        String::new()
674→    };
675→
676→    // Extract tags and summary
677→    let tags = extract_tags_from_spec(&spec_content);
678→    let spec_summary = extract_summary_from_spec(&spec_content);
679→
680→    // Get audit directory for file pattern extraction
681→    let audit_dir = forge_dir.join("audit");
682→
683→    // Build phase stats with enhanced data
684→    let mut phase_stats = Vec::new();
685→    for phase in &phases_file.phases {
686→        // Find the completion entry for this phase
687→        let completed_entry = entries
688→            .iter()
689→            .rev()
690→            .find(|e| e.phase == phase.number && e.status == "completed");
691→
692→        let actual_iterations = completed_entry.map(|e| e.iteration).unwrap_or(phase.budget);
693→
694→        // Classify the phase type
695→        let phase_type = PhaseType::classify(&phase.name);
696→
697→        // Extract file patterns from audit trail
698→        let file_patterns = extract_file_patterns_for_phase(&audit_dir, &phase.number);
699→
700→        phase_stats.push(PhaseStat {
701→            name: phase.name.clone(),
702→            promise: phase.promise.clone(),
703→            actual_iterations,
704→            original_budget: phase.budget,
705→            phase_type,
706→            file_patterns,
707→            common_errors: Vec::new(), // TODO: Extract from logs
708→        });
709→    }
710→
711→    // Calculate success rate
712→    let total_phases = phases_file.phases.len();
713→    let completed_phases = entries
714→        .iter()
715→        .filter(|e| e.status == "completed")
716→        .map(|e| &e.phase)
717→        .collect::<std::collections::HashSet<_>>()
718→        .len();
719→
720→    let success_rate = if total_phases > 0 {
721→        completed_phases as f64 / total_phases as f64
722→    } else {
723→        0.0
724→    };
725→
726→    let mut pattern = Pattern {
727→        name,
728→        created_at: Utc::now(),
729→        tags,
730→        spec_summary,
731→        phase_stats,
732→        total_phases,
733→        success_rate,
734→        type_stats: HashMap::new(),
735→        common_file_patterns: Vec::new(),
736→    };
737→
738→    // Compute aggregate statistics
739→    pattern.compute_type_stats();
740→    pattern.compute_common_file_patterns();
741→
742→    Ok(pattern)
743→}
