 5→pub async fn cmd_factory(
 6→    port: u16,
 7→    init: bool,
 8→    db_path: std::path::PathBuf,
 9→    open: bool,
10→    dev: bool,
11→) -> Result<()> {
12→    if init {
13→        // Just initialize the database
14→        if let Some(parent) = db_path.parent() {
15→            std::fs::create_dir_all(parent)?;
16→        }
17→        forge::factory::db::FactoryDb::new(&db_path)?;
18→        println!("Factory database initialized at {}", db_path.display());
19→        return Ok(());
20→    }
21→
22→    // Spawn browser open before starting the server (which blocks)
23→    // Skip in dev mode (no browser inside Docker containers)
24→    if open && !dev {
25→        let url = format!("http://localhost:{}", port);
26→        tokio::spawn(async move {
27→            // Small delay to let the server start binding
28→            tokio::time::sleep(tokio::time::Duration::from_millis(500)).await;
29→            if let Err(e) = open::that(&url) {
30→                eprintln!("Failed to open browser: {}", e);
31→            }
32→        });
33→    }
34→
35→    let project_path = std::env::current_dir()
36→        .map(|p| p.to_string_lossy().to_string())
37→        .unwrap_or_else(|_| ".".to_string());
38→
39→    forge::factory::server::start_server(forge::factory::server::ServerConfig {
40→        port,
41→        db_path,
42→        project_path,
43→        dev_mode: dev,
44→    })
45→    .await?;
46→
47→    Ok(())
48→}
