 83→/// Start the factory server.
 84→pub async fn start_server(config: ServerConfig) -> Result<()> {
 85→    // Ensure parent directory exists for DB
 86→    if let Some(parent) = config.db_path.parent() {
 87→        std::fs::create_dir_all(parent).context("Failed to create database directory")?;
 88→    }
 89→
 90→    let db = FactoryDb::new(&config.db_path).context("Failed to initialize factory database")?;
 91→    let (ws_tx, _rx) = broadcast::channel::<String>(256);
 92→    let github_client_id = std::env::var("GITHUB_CLIENT_ID").ok();
 93→
 94→    // Check if Docker sandboxing is enabled
 95→    let sandbox = if std::env::var("FORGE_SANDBOX").unwrap_or_default() == "true" {
 96→        match DockerSandbox::new("forge:local".to_string()).await {
 97→            Some(sandbox) => {
 98→                eprintln!("[factory] Docker sandbox enabled");
 99→                let s = Arc::new(sandbox);
100→                if let Ok(pruned) = s.prune_stale_containers(7200).await
101→                    && pruned > 0
102→                {
103→                    eprintln!("[factory] Pruned {} stale pipeline containers", pruned);
104→                }
105→                Some(s)
106→            }
107→            None => {
108→                eprintln!(
109→                    "[factory] FORGE_SANDBOX=true but Docker is not available, falling back to local execution"
110→                );
111→                None
112→            }
113→        }
114→    } else {
115→        None
116→    };
117→
118→    let pipeline_runner = PipelineRunner::new(&config.project_path, sandbox);
119→    let db_handle = DbHandle::new(db);
120→
121→    // Recover orphaned runs from a previous server instance
122→    match db_handle.lock_sync() {
123→        Ok(db) => match db.recover_orphaned_runs() {
124→            Ok(0) => {}
125→            Ok(n) => eprintln!(
126→                "[factory] Recovered {} orphaned pipeline run(s) from previous session",
127→                n
128→            ),
129→            Err(e) => eprintln!("[factory] Warning: failed to recover orphaned runs: {}", e),
130→        },
131→        Err(e) => eprintln!(
132→            "[factory] Warning: could not acquire DB lock for orphan recovery: {}",
133→            e
134→        ),
135→    }
136→
137→    let persisted_token = db_handle
138→        .lock_sync()
139→        .context("Failed to acquire DB lock during startup")?
140→        .get_setting("github_token")
141→        .ok()
142→        .flatten();
143→
144→    let state = Arc::new(AppState {
145→        db: db_handle,
146→        ws_tx,
147→        pipeline_runner,
148→        github_client_id,
149→        github_token: std::sync::Mutex::new(persisted_token),
150→    });
151→
152→    let state_for_shutdown = Arc::clone(&state);
153→    let mut app = build_router(state);
154→
155→    if config.dev_mode {
156→        app = app.layer(CorsLayer::permissive());
157→    }
158→
159→    let host = if config.dev_mode {
160→        "0.0.0.0"
161→    } else {
162→        "127.0.0.1"
163→    };
164→    let addr = format!("{}:{}", host, config.port);
165→    let listener = tokio::net::TcpListener::bind(&addr)
166→        .await
167→        .with_context(|| format!("Failed to bind to {}", addr))?;
168→
169→    let local_addr = listener.local_addr()?;
170→    println!("Forge Factory running at http://{}", local_addr);
171→
172→    axum::serve(listener, app)
173→        .with_graceful_shutdown(shutdown_signal())
174→        .await
175→        .context("Server error")?;
176→
177→    // Stop all active pipeline containers/processes
178→    state_for_shutdown.pipeline_runner.shutdown().await;
179→
180→    println!("Server shut down gracefully.");
181→    Ok(())
182→}
