1451→    run_id: i64,
1452→    project_path: &str,
1453→    issue_title: &str,
1454→    issue_description: &str,
1455→    running_processes: &Arc<tokio::sync::Mutex<HashMap<i64, RunHandle>>>,
1456→    db: &DbHandle,
1457→    tx: &broadcast::Sender<String>,
1458→) -> Result<String> {
1459→    let mut cmd = build_execution_command(project_path, issue_title, issue_description);
1460→    let mut child = cmd.spawn().context("Failed to spawn pipeline process")?;
1461→
1462→    // Take stdout before storing child — we need ownership of the stdout handle
1463→    let stdout = child
1464→        .stdout
1465→        .take()
1466→        .context("Failed to capture stdout from child process")?;
1467→
1468→    // Store the child handle for cancellation
1469→    {
1470→        let mut processes = running_processes.lock().await;
1471→        processes.insert(run_id, RunHandle::Process(child));
1472→    }
1473→
1474→    // Read stdout line by line, looking for progress updates
1475→    let reader = BufReader::new(stdout);
1476→    let mut lines = reader.lines();
1477→    let mut all_output = String::new();
1478→    let mut last_output_broadcast = std::time::Instant::now() - std::time::Duration::from_secs(1);
1479→
1480→    while let Some(line) = lines
1481→        .next_line()
1482→        .await
1483→        .context("Failed to read stdout line")?
1484→    {
1485→        all_output.push_str(&line);
1486→        all_output.push('\n');
1487→
1488→        // Try to parse as DAG executor PhaseEvent first (from forge swarm)
1489→        if let Some(event) = try_parse_phase_event(&line) {
1490→            process_phase_event(&event, run_id, db, tx).await;
1491→            continue;
1492→        }
1493→
1494→        // Fall back to simple progress JSON (from claude --print)
1495→        if let Some(progress) = try_parse_progress(&line) {
1496→            // Update DB with progress
1497→            {
1498→                let phase_count = progress.phase_count;
1499→                let phase = progress.phase;
1500→                let iteration = progress.iteration;
1501→                if let Err(e) = db
1502→                    .call(move |db| {
1503→                        db.update_pipeline_progress(run_id, phase_count, phase, iteration)
1504→                    })
1505→                    .await
1506→                {
1507→                    broadcast_message(
1508→                        tx,
1509→                        &WsMessage::PipelineError {
1510→                            run_id,
1511→                            message: format!("Failed to update pipeline progress: {:#}", e),
1512→                        },
1513→                    );
1514→                }
1515→            }
1516→
1517→            // Compute a rough percentage
1518→            let percent = compute_percent(&progress);
1519→
1520→            // Broadcast progress event
1521→            broadcast_message(
1522→                tx,
1523→                &WsMessage::PipelineProgress {
1524→                    run_id,
1525→                    phase: progress.phase.unwrap_or(0),
1526→                    iteration: progress.iteration.unwrap_or(0),
1527→                    percent,
1528→                },
1529→            );
1530→        } else if !line.is_empty() {
1531→            let event = parse_stream_json_line(&line);
1532→            match event {
1533→                StreamJsonEvent::Skip => {}
1534→                StreamJsonEvent::Text { ref text } | StreamJsonEvent::Thinking { ref text } => {
1535→                    // Throttle text/thinking events to 200ms
1536→                    if last_output_broadcast.elapsed() >= std::time::Duration::from_millis(200)
1537→                        && !text.is_empty()
1538→                    {
1539→                        let content_type = match &event {
1540→                            StreamJsonEvent::Thinking { .. } => "thinking",
1541→                            _ => "text",
1542→                        };
1543→                        broadcast_message(
1544→                            tx,
1545→                            &WsMessage::PipelineOutputEvent {
1546→                                run_id,
1547→                                content_type: content_type.to_string(),
1548→                                content: text.clone(),
1549→                                tool_id: None,

