 58→/// Parsed output event from agent stdout
 59→#[derive(Debug, Clone)]
 60→pub struct ParsedEvent {
 61→    pub event_type: AgentEventType,
 62→    pub content: String,
 63→    pub metadata: Option<serde_json::Value>,
 64→}
 65→
 66→pub struct OutputParser;
 67→
 68→impl OutputParser {
 69→    /// Parse a single line of agent stdout into a structured event.
 70→    ///
 71→    /// Priority order:
 72→    /// 1. Signal tags (`<progress>`, `<blocker>`, `<pivot>`) → event_type "signal"
 73→    /// 2. JSON with `"type": "thinking"` → event_type "thinking"
 74→    /// 3. JSON with `"type": "tool_use"|"tool_result"` → event_type "action"
 75→    /// 4. Other JSON with `"type"` field → event_type "output"
 76→    /// 5. Anything else → event_type "output" (plain text)
 77→    ///
 78→    /// Note: Valid JSON without a "type" field falls through to rule 5 (plain text)
 79→    /// and its metadata will be None, even though the JSON was successfully parsed.
 80→    /// This is intentional -- only typed JSON is captured with its parsed value.
 81→    pub fn parse_line(line: &str) -> ParsedEvent {
 82→        let trimmed = line.trim();
 83→
 84→        // Check for signal tags: <progress>, <blocker>, <pivot>
 85→        for signal in &["progress", "blocker", "pivot"] {
 86→            let open_tag = format!("<{}>", signal);
 87→            let close_tag = format!("</{}>", signal);
 88→            if let Some(start) = trimmed.find(&open_tag) {
 89→                let content_start = start + open_tag.len();
 90→                let content = if let Some(end) = trimmed.find(&close_tag) {
 91→                    &trimmed[content_start..end]
 92→                } else {
 93→                    &trimmed[content_start..]
 94→                };
 95→                return ParsedEvent {
 96→                    event_type: AgentEventType::Signal,
 97→                    content: content.to_string(),
 98→                    metadata: Some(serde_json::json!({"signal_type": signal})),
 99→                };
100→            }
101→        }
102→
103→        // Use the stream-json parser to classify the event
104→        match parse_stream_json_line(trimmed) {
105→            StreamJsonEvent::Skip => ParsedEvent {
106→                event_type: AgentEventType::Output,
107→                content: String::new(),
108→                metadata: None,
109→            },
110→            StreamJsonEvent::Text { text } => ParsedEvent {
111→                event_type: AgentEventType::Output,
112→                content: text,
113→                metadata: None,
114→            },
115→            StreamJsonEvent::Thinking { text } => ParsedEvent {
116→                event_type: AgentEventType::Thinking,
117→                content: text,
118→                metadata: None,
119→            },
120→            StreamJsonEvent::ToolStart {
121→                tool_name,
122→                tool_id,
123→                input_summary,
124→            } => {
125→                let summary = if input_summary.is_empty() {
126→                    tool_name.clone()
127→                } else {
128→                    format!("{} {}", tool_name, input_summary)
129→                };
130→                // Try to extract file change metadata from the original JSON
131→                let metadata = if let Ok(json) = serde_json::from_str::<serde_json::Value>(trimmed)
132→                {
133→                    let input = json
134→                        .get("content_block")
135→                        .and_then(|cb| cb.get("input"))
136→                        .or_else(|| json.get("input"))
137→                        .or_else(|| {
138→                            json.get("content")
139→                                .and_then(|c| c.as_array())
140→                                .and_then(|arr| {
141→                                    arr.iter().find(|b| {
142→                                        b.get("type").and_then(|t| t.as_str()) == Some("tool_use")
143→                                    })
144→                                })
145→                                .and_then(|b| b.get("input"))
146→                        });
147→                    let file_change = extract_file_change(&tool_name, input);
148→                    Some(serde_json::json!({
149→                        "tool": tool_name,
150→                        "tool_id": tool_id,
151→                        "input_summary": input_summary,
152→                        "file_change": file_change.as_ref().map(|(path, action)| {
153→                            serde_json::json!({"path": path, "action": action})
154→                        }),
155→                    }))
156→                } else {
157→                    Some(serde_json::json!({"tool": tool_name, "tool_id": tool_id}))
158→                };
159→                ParsedEvent {
160→                    event_type: AgentEventType::Action,
161→                    content: summary,
162→                    metadata,
163→                }
164→            }
165→            StreamJsonEvent::ToolEnd {
166→                tool_id,
167→                output_preview,
168→            } => ParsedEvent {
169→                event_type: AgentEventType::Output,
170→                content: output_preview,
171→                metadata: Some(serde_json::json!({"tool_id": tool_id})),
172→            },
173→        }
174→    }
175→}
