642→    /// Merge a task branch into the target branch.
643→    ///
644→    /// WARNING: This performs `git checkout` on the main project directory.
645→    /// It is NOT safe for concurrent use -- callers must ensure exclusive access
646→    /// to the project directory during merge operations.
647→    /// See `GitLockMap` in `pipeline.rs` which provides per-project mutex serialization for callers.
648→    pub async fn merge_branch(&self, task_branch: &str, target_branch: &str) -> Result<bool> {
649→        // Record current HEAD so we can restore on failure
650→        let head_output = Command::new("git")
651→            .args(["rev-parse", "--abbrev-ref", "HEAD"])
652→            .current_dir(&self.project_path)
653→            .output()
654→            .await
655→            .context("Failed to determine current branch before merge")?;
656→        let original_branch = String::from_utf8_lossy(&head_output.stdout)
657→            .trim()
658→            .to_string();
659→
660→        // Checkout target branch first
661→        let checkout = Command::new("git")
662→            .args(["checkout", target_branch])
663→            .current_dir(&self.project_path)
664→            .output()
665→            .await
666→            .context("Failed to checkout target branch for merge")?;
667→        if !checkout.status.success() {
668→            let stderr = String::from_utf8_lossy(&checkout.stderr);
669→            anyhow::bail!("Failed to checkout {}: {}", target_branch, stderr);
670→        }
671→
672→        // Then merge
673→        let output = Command::new("git")
674→            .args([
675→                "merge",
676→                "--no-ff",
677→                "-m",
678→                &format!("Merge {}", task_branch),
679→                task_branch,
680→            ])
681→            .current_dir(&self.project_path)
682→            .output()
683→            .await
684→            .context("Failed to merge branch")?;
685→
686→        if !output.status.success() {
687→            let stderr = String::from_utf8_lossy(&output.stderr);
688→            eprintln!(
689→                "[agent] Merge of {} into {} failed: {}",
690→                task_branch,
691→                target_branch,
692→                stderr.trim()
693→            );
694→
695→            // Merge failed — abort and restore original branch
696→            let abort_output = Command::new("git")
697→                .args(["merge", "--abort"])
698→                .current_dir(&self.project_path)
699→                .output()
700→                .await;
701→
702→            match abort_output {
703→                Err(e) => {
704→                    anyhow::bail!(
705→                        "Merge of {} failed AND merge --abort could not execute: {}",
706→                        task_branch,
707→                        e
708→                    );
709→                }
710→                Ok(output) if !output.status.success() => {
711→                    let stderr = String::from_utf8_lossy(&output.stderr);
712→                    anyhow::bail!(
713→                        "Merge of {} failed AND merge --abort failed: {}",
714→                        task_branch,
715→                        stderr.trim()
716→                    );
717→                }
718→                Ok(_) => {} // abort succeeded, continue to return Ok(false)
719→            }
720→            if original_branch != target_branch
721→                && let Err(e) = Command::new("git")
722→                    .args(["checkout", &original_branch])
723→                    .current_dir(&self.project_path)
724→                    .output()

