 28→/// Policy for auto-promoting issues after pipeline completion.
 29→pub struct AutoPromotePolicy;
 30→
 31→impl AutoPromotePolicy {
 32→    /// Decide where to move an issue based on pipeline results.
 33→    ///
 34→    /// - `pipeline_succeeded`: did the pipeline complete without failures?
 35→    /// - `has_review_warnings`: did any review produce warnings?
 36→    /// - `arbiter_proceeded`: did the arbiter have to PROCEED past findings?
 37→    /// - `fix_attempts`: how many fix cycles were needed?
 38→    pub fn decide(
 39→        pipeline_succeeded: bool,
 40→        has_review_warnings: bool,
 41→        arbiter_proceeded: bool,
 42→        fix_attempts: u32,
 43→    ) -> PromoteDecision {
 44→        if !pipeline_succeeded {
 45→            return PromoteDecision::Failed;
 46→        }
 47→        if has_review_warnings || arbiter_proceeded || fix_attempts > 0 {
 48→            return PromoteDecision::InReview;
 49→        }
 50→        PromoteDecision::Done
 51→    }
 52→}
