 54→fn translate_host_path_to_container(path: &str) -> String {
 55→    if path.contains("/.forge/repos/")
 56→        && !path.starts_with("/app/")
 57→        && let Some(pos) = path.find("/.forge/repos/")
 58→    {
 59→        return format!("/app{}", &path[pos..]);
 60→    }
 61→    path.to_string()
 62→}
