 64→/// Per-project mutex map that serializes git-mutating operations.
 65→/// Long-running agent execution remains parallel — only short git
 66→/// mutations (checkout, merge, push) are serialized.
 67→#[derive(Clone, Default)]
 68→pub struct GitLockMap {
 69→    locks: Arc<tokio::sync::Mutex<HashMap<String, Arc<tokio::sync::Mutex<()>>>>>,
 70→}
 71→
 72→impl GitLockMap {
 73→    pub async fn get(&self, project_path: &str) -> Arc<tokio::sync::Mutex<()>> {
 74→        let project_path = translate_host_path_to_container(project_path);
 75→        let canonical = match tokio::fs::canonicalize(&project_path).await {
 76→            Ok(p) => p.to_string_lossy().to_string(),
 77→            Err(e) => {
 78→                eprintln!(
 79→                    "[pipeline] Failed to canonicalize '{}': {}. Using raw path for git lock.",
 80→                    project_path, e
 81→                );
 82→                project_path.trim_end_matches('/').to_string()
 83→            }
 84→        };
 85→        let mut map = self.locks.lock().await;
 86→        map.entry(canonical)
 87→            .or_insert_with(|| Arc::new(tokio::sync::Mutex::new(())))
 88→            .clone()
 89→    }
 90→}
